from flask import Flask, request, session, redirect, url_for
from flask_sqlalchemy import SQLAlchemy
import secrets
import string
from email.mime.multipart import MIMEMultipart
from email.mime.text import MIMEText
import smtplib

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(64), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password = db.Column(db.String(128), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)

class MFAReset(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    token = db.Column(db.String(32), nullable=False)

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    email = request.form['email']
    user = User.query.filter_by(email=email).first()
    if not user:
        return 'User not found'
    
    mfa_reset = MFAReset(user_id=user.id, token=secrets.token_urlsafe(32))
    db.session.add(mfa_reset)
    db.session.commit()

    msg = MIMEMultipart()
    msg['From'] = 'your-email@gmail.com'
    msg['To'] = email
    msg['Subject'] = 'MFA Reset Link'

    body = f'Click this link to reset your MFA: http://localhost:5000/reset-mfa-confirm/{mfa_reset.token}'
    msg.attach(MIMEText(body, 'plain'))

    server = smtplib.SMTP('smtp.gmail.com', 587)
    server.starttls()
    server.login(msg['From'], 'your-password')
    text = msg.as_string()
    server.sendmail(msg['From'], email, text)
    server.quit()

    return 'MFA reset link sent'

@app.route('/reset-mfa-confirm/<token>', methods=['GET'])
def confirm_reset(token):
    mfa_reset = MFAReset.query.filter_by(token=token).first()
    if not mfa_reset:
        return 'Invalid token'
    
    user = User.query.get(mfa_reset.user_id)
    user.mfa_enabled = False
    db.session.commit()

    return 'MFA disabled'

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.form['email']
    user = User.query.filter_by(email=email).first()
    if not user:
        return 'User not found'
    
    user.mfa_enabled = True
    db.session.commit()

    return 'MFA enabled'

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    email = request.form['email']
    user = User.query.filter_by(email=email).first()
    if not user:
        return 'User not found'
    
    user.mfa_enabled = False
    db.session.commit()

    return 'MFA disabled'

if __name__ == '__main__':
    app.run(debug=True)